  1→import React, { useEffect } from 'react';
  2→import { MapContainer, Marker, Popup, TileLayer, useMap } from 'react-leaflet';
  3→import L from 'leaflet';
  4→import { Category, DataPoint } from '../../types';
  5→import type { MapScope } from '../../shared/types';
  6→import { LEGACY_CATEGORY_MAP, VERTICALS } from '../../shared/verticals';
  7→
  8→type MapPointGroup = {
  9→  key: string;
 10→  latitude: number;
 11→  longitude: number;
 12→  points: DataPoint[];
 13→};
 14→
 15→interface Props {
 16→  mapScope: MapScope;
 17→  mapCenter: [number, number];
 18→  mapZoom: number;
 19→  mapMinZoom: number;
 20→  mapBounds: [[number, number], [number, number]] | undefined;
 21→  mapPointGroups: MapPointGroup[];
 22→  selectedCityLabel: string;
 23→  onSelectPoint: (point: DataPoint) => void;
 24→  categoryLabel: (type: Category) => string;
 25→  formatExplorerPrimaryMeta: (point: DataPoint) => string;
 26→  formatPharmacyOpenStatus: (point: DataPoint) => string | null;
 27→  language: 'en' | 'fr';
 28→  t: (en: string, fr: string) => string;
 29→  isLowEndDevice: boolean;
 30→}
 31→
 32→const createMarkerIcon = (color: string) =>
 33→  L.divIcon({
 34→    className: '',
 35→    html: `<div style="width:26px;height:26px;border-radius:9999px;background:${color};border:2px solid #ffffff;box-shadow:0 8px 16px rgba(15,43,70,0.35);display:flex;align-items:center;justify-content:center;"></div>`,
 36→    iconSize: [26, 26],
 37→    iconAnchor: [13, 13]
 38→  });
 39→
 40→const clusterIconCache = new Map<string, L.DivIcon>();
 41→
 42→const getClusterIcon = (color: string, count: number) => {
 43→  const key = `${color}_${count}`;
 44→  const cached = clusterIconCache.get(key);
 45→  if (cached) return cached;
 46→  const icon = L.divIcon({
 47→    className: '',
 48→    html: `<div style="min-width:28px;height:28px;padding:0 8px;border-radius:9999px;background:${color};border:2px solid #ffffff;box-shadow:0 8px 16px rgba(15,43,70,0.35);display:flex;align-items:center;justify-content:center;color:#ffffff;font-size:11px;font-weight:700;line-height:1;">${count}</div>`,
 49→    iconSize: [28, 28],
 50→    iconAnchor: [14, 14]
 51→  });
 52→  clusterIconCache.set(key, icon);
 53→  return icon;
 54→};
 55→
 56→const markerIconCache = new Map<string, L.DivIcon>();
 57→
 58→const getMarkerIconForType = (type: Category): L.DivIcon => {
 59→  const verticalId = LEGACY_CATEGORY_MAP[type] ?? type;
 60→  const color = VERTICALS[verticalId]?.color ?? '#374151';
 61→  const cached = markerIconCache.get(color);
 62→  if (cached) return cached;
 63→  const icon = createMarkerIcon(color);
 64→  markerIconCache.set(color, icon);
 65→  return icon;
 66→};
 67→
 68→const MapSizeSync: React.FC<{ active: boolean }> = ({ active }) => {
 69→  const map = useMap();
 70→
 71→  useEffect(() => {
 72→    if (!active) return;
 73→    const rafId = requestAnimationFrame(() => {
 74→      map.invalidateSize({ animate: false });
 75→    });
 76→    const timeoutId = window.setTimeout(() => {
 77→      map.invalidateSize({ animate: false });
 78→    }, 140);
 79→
 80→    return () => {
 81→      cancelAnimationFrame(rafId);
 82→      window.clearTimeout(timeoutId);
 83→    };
 84→  }, [active, map]);
 85→
 86→  return null;
 87→};
 88→
 89→const HomeMap: React.FC<Props> = ({
 90→  mapScope,
 91→  mapCenter,
 92→  mapZoom,
 93→  mapMinZoom,
 94→  mapBounds,
 95→  mapPointGroups,
 96→  selectedCityLabel,
 97→  onSelectPoint,
 98→  categoryLabel,
 99→  formatExplorerPrimaryMeta,
100→  formatPharmacyOpenStatus,
101→  language,
102→  t,
103→  isLowEndDevice
104→}) => {
105→  return (
106→    <div className="flex-1 bg-[#e7eef4] relative overflow-hidden z-0 min-h-0">
107→      <MapContainer
108→        key={`map-${mapScope}`}
109→        center={mapCenter}
110→        zoom={mapZoom}
111→        minZoom={mapMinZoom}
112→        maxBounds={mapBounds}
113→        maxBoundsViscosity={mapBounds ? 1.0 : undefined}
114→        scrollWheelZoom
115→        preferCanvas={isLowEndDevice}
116→        zoomAnimation={!isLowEndDevice}
117→        fadeAnimation={!isLowEndDevice}
118→        markerZoomAnimation={!isLowEndDevice}
119→        className="absolute inset-0 h-full w-full"
120→      >
121→        <MapSizeSync active />
122→        <TileLayer
123→          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
124→          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
125→        />
126→        {mapPointGroups.map((group) => {
127→          const singlePoint = group.points.length === 1 ? group.points[0] : null;
128→          const icon = singlePoint
129→            ? getMarkerIconForType(singlePoint.type)
130→            : (() => {
131→              const types = new Set(group.points.map((p) => LEGACY_CATEGORY_MAP[p.type] ?? p.type));
132→              const color = types.size === 1
133→                ? (VERTICALS[Array.from(types)[0]]?.color ?? '#c86b4a')
134→                : '#c86b4a';
135→              return getClusterIcon(color, group.points.length);
136→            })();
137→
138→          return (
139→            <Marker
140→              key={group.key}
141→              position={[group.latitude, group.longitude]}
142→              icon={icon}
143→            >
144→              <Popup>
145→                {singlePoint ? (
146→                  <div className="space-y-1">
147→                    <span className="text-[9px] font-bold uppercase tracking-widest text-[#0f2b46]">
148→                      {categoryLabel(singlePoint.type)}
149→                    </span>
150→                    <p className="text-sm font-semibold text-gray-900">{singlePoint.name}</p>
151→                    <p className="text-[10px] text-gray-600">{formatExplorerPrimaryMeta(singlePoint)}</p>
152→                    {singlePoint.type === Category.PHARMACY && (
153→                      <p className="text-[10px] text-gray-500">{formatPharmacyOpenStatus(singlePoint)}</p>
154→                    )}
155→                    <button
156→                      className="mt-2 w-full rounded-lg bg-[#0f2b46] px-2 py-1 text-[10px] font-bold uppercase tracking-widest text-white"
157→                      onClick={() => onSelectPoint(singlePoint)}
158→                    >
159→                      {t('View Details', 'Voir details')}
160→                    </button>
161→                  </div>
162→                ) : (
163→                  <div className="space-y-2 min-w-[220px]">
164→                    <p className="text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
165→                      {language === 'fr' ? `${group.points.length} points au meme endroit` : `${group.points.length} points at this location`}
166→                    </p>
167→                    <div className="space-y-1.5">
168→                      {group.points.map((point) => (
169→                        <button
170→                          key={point.id}
171→                          className="w-full rounded-lg border border-gray-100 px-2 py-1.5 text-left hover:bg-gray-50"
172→                          onClick={() => onSelectPoint(point)}
173→                        >
174→                          <p className="text-[11px] font-semibold text-gray-900 truncate">{point.name}</p>
175→                          <p className="text-[9px] uppercase tracking-wider text-gray-500">
176→                            {categoryLabel(point.type)}
177→                          </p>
178→                        </button>
179→                      ))}
180→                    </div>
181→                  </div>
182→                )}
183→              </Popup>
184→            </Marker>
185→          );
186→        })}
187→      </MapContainer>
188→      <div className="absolute inset-x-4 top-4 z-20 bg-white/95 backdrop-blur rounded-xl p-3 border border-gray-100 shadow-sm">
189→        <div className="flex items-center justify-between">
190→          <div>
191→            <p className="text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
192→              {mapScope === 'bonamoussadi'
193→                ? t('Bonamoussadi Geofence', 'Geofence Bonamoussadi')
194→                : mapScope === 'cameroon'
195→                  ? t('Cameroon Coverage', 'Couverture Cameroun')
196→                  : t('Global Coverage', 'Couverture mondiale')}
197→            </p>
198→            <p className="text-xs text-gray-500">
199→              {mapScope === 'bonamoussadi' ? t('Map blocked to', 'Carte bloquee sur') : t('Map unlocked to', 'Carte debloquee sur')} {selectedCityLabel}
200→            </p>
201→          </div>
202→          <div className="w-2 h-2 rounded-full bg-[#4c7c59] animate-pulse"></div>
203→        </div>
204→      </div>
205→    </div>
206→  );
207→};
208→
209→export default HomeMap;
