  1→import React, { useEffect, useMemo, useState } from 'react';
  2→import {
  3→  ArrowLeft,
  4→  BarChart3,
  5→  Medal,
  6→  Share2,
  7→  ShieldCheck,
  8→  ThermometerSun,
  9→  Users
 10→} from 'lucide-react';
 11→import {
 12→  BarChart,
 13→  Bar,
 14→  Cell,
 15→  ResponsiveContainer,
 16→  XAxis,
 17→  YAxis,
 18→  Tooltip,
 19→  PieChart,
 20→  Pie
 21→} from 'recharts';
 22→import { getSession } from '../../lib/client/auth';
 23→import { apiJson } from '../../lib/client/api';
 24→import type { LeaderboardEntry, MapScope, PointEvent, ProjectedPoint, SubmissionCategory } from '../../shared/types';
 25→import { categoryPluralLabel, VERTICAL_IDS, VERTICALS } from '../../shared/verticals';
 26→
 27→interface Props {
 28→  onBack: () => void;
 29→  onAdmin?: () => void;
 30→  onAgentPerformance?: () => void;
 31→  onDeltaDashboard?: () => void;
 32→  isAdmin?: boolean;
 33→  language: 'en' | 'fr';
 34→}
 35→
 36→type HeatLevel = 'High' | 'Medium' | 'Low';
 37→
 38→const HEATMAP_COLORS: Record<HeatLevel, string> = {
 39→  High: 'bg-[#4c7c59]',
 40→  Medium: 'bg-[#c86b4a]',
 41→  Low: 'bg-gray-200'
 42→};
 43→
 44→const normalizeMapScope = (scope: unknown, isAdminMode: boolean): MapScope => {
 45→  if (isAdminMode) return 'global';
 46→  if (scope === 'cameroon' || scope === 'global') return scope;
 47→  return 'bonamoussadi';
 48→};
 49→
 50→const Analytics: React.FC<Props> = ({ onBack, onAdmin, onAgentPerformance, onDeltaDashboard, isAdmin, language }) => {
 51→  const adminMode = Boolean(isAdmin);
 52→  const [adminName, setAdminName] = useState<string | null>(null);
 53→  const [adminEmail, setAdminEmail] = useState<string | null>(null);
 54→  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
 55→  const [isLoadingLeaderboard, setIsLoadingLeaderboard] = useState(true);
 56→  const [isLoadingAdminData, setIsLoadingAdminData] = useState(false);
 57→  const [completionRate, setCompletionRate] = useState(0);
 58→  const [activeContributors, setActiveContributors] = useState(0);
 59→  const [categoryData, setCategoryData] = useState<Array<{ name: string; value: number; color: string }>>([]);
 60→  const [heatmap, setHeatmap] = useState<HeatLevel[][]>([
 61→    ['Low', 'Low', 'Low', 'Low'],
 62→    ['Low', 'Low', 'Low', 'Low'],
 63→    ['Low', 'Low', 'Low', 'Low']
 64→  ]);
 65→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 66→
 67→  const categorylabel = (category: SubmissionCategory): string => {
 68→    return categoryPluralLabel(category, language);
 69→  };
 70→
 71→  useEffect(() => {
 72→    if (!adminMode) return;
 73→    const loadSession = async () => {
 74→      const session = await getSession();
 75→      setAdminName(session?.user?.name ?? null);
 76→      setAdminEmail(session?.user?.email ?? null);
 77→    };
 78→    void loadSession();
 79→  }, [adminMode]);
 80→
 81→  useEffect(() => {
 82→    const loadLeaderboard = async () => {
 83→      try {
 84→        setIsLoadingLeaderboard(true);
 85→        const data = await apiJson<LeaderboardEntry[]>('/api/leaderboard');
 86→        setLeaderboard(Array.isArray(data) ? data : []);
 87→      } catch {
 88→        setLeaderboard([]);
 89→      } finally {
 90→        setIsLoadingLeaderboard(false);
 91→      }
 92→    };
 93→
 94→    void loadLeaderboard();
 95→  }, []);
 96→
 97→  useEffect(() => {
 98→    if (!adminMode) return;
 99→    const loadAdminAnalytics = async () => {
100→      try {
101→        setIsLoadingAdminData(true);
102→        const scope = normalizeMapScope('global', true);
103→
104→        const pointParams = new URLSearchParams();
105→        if (scope !== 'bonamoussadi') pointParams.set('scope', scope);
106→        const pointsPath = pointParams.size > 0 ? `/api/submissions?${pointParams.toString()}` : '/api/submissions';
107→
108→        const eventParams = new URLSearchParams({ view: 'events' });
109→        if (scope !== 'bonamoussadi') eventParams.set('scope', scope);
110→        const eventsPath = `/api/submissions?${eventParams.toString()}`;
111→
112→        const [points, events] = await Promise.all([
113→          apiJson<ProjectedPoint[]>(pointsPath),
114→          apiJson<PointEvent[]>(eventsPath)
115→        ]);
116→
117→        const safePoints = Array.isArray(points) ? points : [];
118→        const safeEvents = Array.isArray(events) ? events : [];
119→
120→        const completed = safePoints.filter((point) => Array.isArray(point.gaps) && point.gaps.length === 0).length;
121→        const completion = safePoints.length > 0 ? Math.round((completed / safePoints.length) * 100) : 0;
122→        setCompletionRate(completion);
123→
124→        const now = Date.now();
125→        const activeWindowMs = 30 * 24 * 60 * 60 * 1000;
126→        const activeUsers = new Set(
127→          safeEvents
128→            .filter((event) => {
129→              const createdAt = new Date(event.createdAt).getTime();
130→              return Number.isFinite(createdAt) && now - createdAt <= activeWindowMs;
131→            })
132→            .map((event) => event.userId)
133→            .filter((userId) => typeof userId === 'string' && userId.trim().length > 0)
134→        );
135→        setActiveContributors(activeUsers.size);
136→
137→        const categoryCounts: Record<string, number> = {};
138→        for (const id of VERTICAL_IDS) categoryCounts[id] = 0;
139→        for (const event of safeEvents) {
140→          if (event.category in categoryCounts) categoryCounts[event.category] += 1;
141→        }
142→        setCategoryData(
143→          VERTICAL_IDS
144→            .filter((id) => (categoryCounts[id] ?? 0) > 0)
145→            .map((id) => ({ name: categorylabel(id as SubmissionCategory), value: categoryCounts[id], color: VERTICALS[id].color }))
146→        );
147→
148→        const categories = VERTICAL_IDS;
149→        const bucketsPerCategory = categories.map(() => [0, 0, 0, 0]);
150→        const heatWindowMs = 24 * 60 * 60 * 1000;
151→        for (const event of safeEvents) {
152→          const timestamp = new Date(event.createdAt).getTime();
153→          if (!Number.isFinite(timestamp) || now - timestamp > heatWindowMs || timestamp > now) continue;
154→          const categoryIndex = categories.indexOf(event.category);
155→          if (categoryIndex === -1) continue;
156→          const bucketIndex = Math.max(0, Math.min(3, Math.floor(new Date(timestamp).getHours() / 6)));
157→          bucketsPerCategory[categoryIndex][bucketIndex] += 1;
158→        }
159→
160→        const maxValue = Math.max(...bucketsPerCategory.flat(), 0);
161→        const toHeatLevel = (value: number): HeatLevel => {
162→          if (maxValue <= 0 || value <= 0) return 'Low';
163→          const ratio = value / maxValue;
164→          if (ratio >= 0.67) return 'High';
165→          if (ratio >= 0.34) return 'Medium';
166→          return 'Low';
167→        };
168→
169→        setHeatmap(
170→          bucketsPerCategory.map((row) => row.map((value) => toHeatLevel(value)))
171→        );
172→      } catch {
173→        setCompletionRate(0);
174→        setActiveContributors(0);
175→        setCategoryData([]);
176→        setHeatmap(VERTICAL_IDS.map(() => ['Low', 'Low', 'Low', 'Low'] as HeatLevel[]));
177→      } finally {
178→        setIsLoadingAdminData(false);
179→      }
180→    };
181→
182→    void loadAdminAnalytics();
183→  }, [adminMode, language]);
184→
185→  const formatLastSeen = (iso: string | null) => {
186→    if (!iso) return t('No date', 'Pas de date');
187→    const date = new Date(iso);
188→    if (Number.isNaN(date.getTime())) return t('No date', 'Pas de date');
189→    const now = Date.now();
190→    const diffMs = now - date.getTime();
191→    const minutes = Math.max(1, Math.round(diffMs / 60000));
192→    if (minutes < 60) return language === 'fr' ? `il y a ${minutes} min` : `${minutes}m ago`;
193→    const hours = Math.round(minutes / 60);
194→    if (hours < 24) return language === 'fr' ? `il y a ${hours}h` : `${hours}h ago`;
195→    const days = Math.round(hours / 24);
196→    return language === 'fr' ? `il y a ${days}j` : `${days}d ago`;
197→  };
198→
199→  const xpDistribution = useMemo(() => {
200→    const buckets = [
201→      { name: '0-100', value: 0, color: '#d5e1eb' },
202→      { name: '100-500', value: 0, color: '#0f2b46' },
203→      { name: '500-1k', value: 0, color: '#4c7c59' },
204→      { name: '1k+', value: 0, color: '#c86b4a' }
205→    ];
206→    for (const entry of leaderboard) {
207→      if (entry.xp < 100) {
208→        buckets[0].value += 1;
209→      } else if (entry.xp < 500) {
210→        buckets[1].value += 1;
211→      } else if (entry.xp < 1000) {
212→        buckets[2].value += 1;
213→      } else {
214→        buckets[3].value += 1;
215→      }
216→    }
217→    return buckets;
218→  }, [leaderboard]);
219→
220→  const topVerticalChampion = useMemo(() => {
221→    if (leaderboard.length === 0) return null;
222→    const totals = new Map<string, number>();
223→    for (const entry of leaderboard) {
224→      Object.entries(entry.verticalBreakdown ?? {}).forEach(([vertical, count]) => {
225→        totals.set(vertical, (totals.get(vertical) ?? 0) + (typeof count === 'number' ? count : 0));
226→      });
227→    }
228→    const sorted = [...totals.entries()].sort((a, b) => b[1] - a[1]);
229→    return sorted[0] ?? null;
230→  }, [leaderboard]);
231→
232→  return (
233→    <div className="flex flex-col h-full bg-[#f9fafb] overflow-y-auto no-scrollbar">
234→      <div className="sticky top-0 z-30 bg-white border-b border-gray-100 px-4 h-14 flex items-center justify-between">
235→        <button onClick={onBack} className="p-2 -ml-2 text-gray-700 hover:text-[#0f2b46] transition-colors">
236→          <ArrowLeft size={20} />
237→        </button>
238→        <h3 className="text-sm font-bold mx-auto">{adminMode ? t('Investor Analytics', 'Analytique investisseur') : t('Leaderboard', 'Classement')}</h3>
239→        <button className="p-2 text-gray-400 absolute right-2">
240→          <Share2 size={20} />
241→        </button>
242→      </div>
243→
244→      <div className="p-4 space-y-6">
245→        {adminMode ? (
246→          <div className="flex items-center justify-between py-2">
247→            <div className="flex items-center space-x-3">
248→              <div className="w-12 h-12 rounded-full border-2 border-white shadow bg-[#e7eef4] overflow-hidden">
249→                <img src="https://picsum.photos/seed/kofi/300/300" alt={t('avatar', 'avatar')} className="w-full h-full object-cover" />
250→              </div>
251→              <div className="flex flex-col">
252→                <h4 className="font-bold text-gray-900 text-sm">
253→                  {adminName || adminEmail || t('Admin', 'Admin')}
254→                </h4>
255→                <div className="flex items-center space-x-1.5">
256→                  <ShieldCheck size={12} className="text-[#4c7c59]" />
257→                  <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('Senior Contributor', 'Contributeur senior')}</span>
258→                </div>
259→              </div>
260→            </div>
261→            {onAdmin && (
262→              <button
263→                onClick={onAdmin}
264→                className="px-3 py-1.5 bg-[#1f2933] text-white text-[10px] font-bold uppercase rounded-xl tracking-wider hover:bg-black transition-colors shadow-sm"
265→              >
266→                {t('Admin', 'Admin')}
267→              </button>
268→            )}
269→          </div>
270→        ) : (
271→          <div className="flex items-center justify-between py-2">
272→            <div className="flex flex-col">
273→              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('Leaderboard', 'Classement')}</span>
274→              <span className="text-sm font-semibold text-gray-900">{t('Top contributors near you', 'Top contributeurs pres de vous')}</span>
275→            </div>
276→          </div>
277→        )}
278→
279→        {adminMode && onDeltaDashboard && (
280→          <div className="grid grid-cols-1 gap-3 lg:grid-cols-2">
281→            <button
282→              onClick={onDeltaDashboard}
283→              className="w-full flex items-center justify-between bg-[#0f2b46] text-white p-4 rounded-2xl shadow-sm hover:bg-[#1a3d5c] transition-colors"
284→            >
285→              <div className="flex items-center space-x-3">
286→                <BarChart3 size={18} />
287→                <div className="text-left">
288→                  <span className="text-xs font-bold block">{t('Delta Intelligence', 'Intelligence Delta')}</span>
289→                  <span className="text-[10px] text-gray-300">{t('Snapshots, trends & anomalies', 'Snapshots, tendances & anomalies')}</span>
290→                </div>
291→              </div>
292→              <ArrowLeft size={16} className="rotate-180" />
293→            </button>
294→            {onAgentPerformance && (
295→              <button
296→                onClick={onAgentPerformance}
297→                className="w-full flex items-center justify-between bg-white border border-gray-100 text-[#0f2b46] p-4 rounded-2xl shadow-sm hover:border-[#0f2b46] transition-colors"
298→              >
299→                <div className="flex items-center space-x-3">
300→                  <Users size={18} />
301→                  <div className="text-left">
302→                    <span className="text-xs font-bold block">{t('Agent Performance', 'Performance agents')}</span>
303→                    <span className="text-[10px] text-gray-500">{t('Quality, fraud & assignment pace', 'Qualite, fraude et rythme des affectations')}</span>
304→                  </div>
305→                </div>
306→                <ArrowLeft size={16} className="rotate-180" />
307→              </button>
308→            )}
309→          </div>
310→        )}
311→
312→        {adminMode && (
313→          <div className="grid grid-cols-2 gap-4">
314→            <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-2">
315→              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('Data Complete', 'Donnees completes')}</span>
316→              <div className="flex items-baseline space-x-1">
317→                <span className="text-xl font-bold text-gray-900">{completionRate}%</span>
318→                <span className="text-[10px] text-[#4c7c59] font-bold">{isLoadingAdminData ? '...' : t('live', 'live')}</span>
319→              </div>
320→            </div>
321→            <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-2">
322→              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('Active Contributors', 'Contributeurs actifs')}</span>
