 45→  const normalizeMapScope = (value: unknown, isAdminMode: boolean): MapScope => {
 46→    if (isAdminMode) return 'global';
 47→    if (value === 'cameroon' || value === 'global') return value;
 48→    return 'bonamoussadi';
 49→  };
 50→  const activeMapScope = normalizeMapScope(profile?.mapScope, Boolean(profile?.isAdmin));
