  1→import React, { useEffect, useMemo, useState } from 'react';
  2→import { ArrowLeft, ShieldCheck, TrendingUp, Users, WalletCards } from 'lucide-react';
  3→import { apiJson } from '../../lib/client/api';
  4→import type { AdminSubmissionEvent, CollectionAssignment } from '../../shared/types';
  5→
  6→interface Props {
  7→  onBack: () => void;
  8→  language: 'en' | 'fr';
  9→}
 10→
 11→interface KpiSummary {
 12→  activeContributors?: number;
 13→  eventsWithFraudCheck?: number;
 14→  mismatchEvents?: number;
 15→  fraudRatePct?: number;
 16→  pendingReview?: number;
 17→  highRiskEvents?: number;
 18→}
 19→
 20→type AgentRow = {
 21→  id: string;
 22→  name: string;
 23→  submissions: number;
 24→  averageQuality: number;
 25→  flagged: number;
 26→  pendingAssignments: number;
 27→  lastSubmissionAt: string | null;
 28→};
 29→
 30→function numericDetail(value: unknown): number {
 31→  return typeof value === 'number' && Number.isFinite(value) ? value : 0;
 32→}
 33→
 34→const AgentPerformance: React.FC<Props> = ({ onBack, language }) => {
 35→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 36→  const [events, setEvents] = useState<AdminSubmissionEvent[]>([]);
 37→  const [assignments, setAssignments] = useState<CollectionAssignment[]>([]);
 38→  const [kpis, setKpis] = useState<KpiSummary | null>(null);
 39→  const [loading, setLoading] = useState(true);
 40→
 41→  useEffect(() => {
 42→    let cancelled = false;
 43→
 44→    const load = async () => {
 45→      try {
 46→        setLoading(true);
 47→        const [eventData, assignmentData, kpiData] = await Promise.all([
 48→          apiJson<AdminSubmissionEvent[]>('/api/submissions?view=admin_events&scope=global'),
 49→          apiJson<CollectionAssignment[]>('/api/user?view=assignments&scope=all'),
 50→          apiJson<KpiSummary>('/api/analytics?view=kpi_summary'),
 51→        ]);
 52→        if (cancelled) return;
 53→        setEvents(Array.isArray(eventData) ? eventData : []);
 54→        setAssignments(Array.isArray(assignmentData) ? assignmentData : []);
 55→        setKpis(kpiData ?? null);
 56→      } catch {
 57→        if (cancelled) return;
 58→        setEvents([]);
 59→        setAssignments([]);
 60→        setKpis(null);
 61→      } finally {
 62→        if (!cancelled) setLoading(false);
 63→      }
 64→    };
 65→
 66→    void load();
 67→    return () => {
 68→      cancelled = true;
 69→    };
 70→  }, []);
 71→
 72→  const agentRows = useMemo<AgentRow[]>(() => {
 73→    const rows = new Map<string, AgentRow>();
 74→    for (const item of events) {
 75→      const details = (item.event.details ?? {}) as Record<string, unknown>;
 76→      const quality = numericDetail(details.confidenceScore);
 77→      const riskScore = numericDetail(details.riskScore);
 78→      const current = rows.get(item.user.id) ?? {
 79→        id: item.user.id,
 80→        name: item.user.name || item.user.email || item.user.id,
 81→        submissions: 0,
 82→        averageQuality: 0,
 83→        flagged: 0,
 84→        pendingAssignments: 0,
 85→        lastSubmissionAt: null,
 86→      };
 87→      current.submissions += 1;
 88→      current.averageQuality += quality;
 89→      if (riskScore >= 60) current.flagged += 1;
 90→      if (!current.lastSubmissionAt || new Date(item.event.createdAt).getTime() > new Date(current.lastSubmissionAt).getTime()) {
 91→        current.lastSubmissionAt = item.event.createdAt;
 92→      }
 93→      rows.set(item.user.id, current);
 94→    }
 95→
 96→    for (const assignment of assignments) {
 97→      const row = rows.get(assignment.agentUserId) ?? {
 98→        id: assignment.agentUserId,
 99→        name: assignment.agentUserId,
100→        submissions: 0,
101→        averageQuality: 0,
102→        flagged: 0,
103→        pendingAssignments: 0,
104→        lastSubmissionAt: null,
105→      };
106→      if (assignment.status === 'pending' || assignment.status === 'in_progress') {
107→        row.pendingAssignments += 1;
108→      }
109→      rows.set(assignment.agentUserId, row);
110→    }
111→
112→    return [...rows.values()]
113→      .map((row) => ({
114→        ...row,
115→        averageQuality: row.submissions > 0 ? Math.round(row.averageQuality / row.submissions) : 0,
116→      }))
117→      .sort((a, b) => {
118→        if (b.submissions !== a.submissions) return b.submissions - a.submissions;
119→        return b.averageQuality - a.averageQuality;
120→      });
121→  }, [assignments, events]);
122→
123→  const activeAgents = agentRows.filter((row) => row.submissions > 0).length;
124→  const avgQuality = agentRows.length > 0 ? Math.round(agentRows.reduce((sum, row) => sum + row.averageQuality, 0) / agentRows.length) : 0;
125→
126→  return (
127→    <div className="flex flex-col h-full bg-[#f9fafb] overflow-y-auto no-scrollbar">
128→      <div className="sticky top-0 z-30 bg-white border-b border-gray-100 px-4 h-14 flex items-center justify-between">
