133→        <div className="w-8" />
134→      </div>
135→
136→      <div className="p-4 space-y-4">
137→        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
138→          <div className="rounded-3xl border border-gray-100 bg-white p-5 shadow-sm">
139→            <div className="inline-flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
140→              <Users size={12} />
141→              {t('Active Agents', 'Agents actifs')}
142→            </div>
143→            <div className="mt-3 text-3xl font-bold text-[#0f2b46]">{loading ? '--' : activeAgents}</div>
144→          </div>
145→          <div className="rounded-3xl border border-gray-100 bg-white p-5 shadow-sm">
146→            <div className="inline-flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
147→              <TrendingUp size={12} />
148→              {t('Avg Quality', 'Qualite moyenne')}
149→            </div>
150→            <div className="mt-3 text-3xl font-bold text-[#4c7c59]">{loading ? '--' : `${avgQuality}%`}</div>
151→          </div>
152→          <div className="rounded-3xl border border-gray-100 bg-white p-5 shadow-sm">
153→            <div className="inline-flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
154→              <ShieldCheck size={12} />
155→              {t('Fraud Rate', 'Taux fraude')}
156→            </div>
157→            <div className="mt-3 text-3xl font-bold text-[#c86b4a]">
158→              {loading ? '--' : `${Math.round(kpis?.fraudRatePct ?? 0)}%`}
159→            </div>
160→          </div>
161→          <div className="rounded-3xl border border-gray-100 bg-white p-5 shadow-sm">
162→            <div className="inline-flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
163→              <WalletCards size={12} />
164→              {t('Pending Review', 'En attente')}
165→            </div>
166→            <div className="mt-3 text-3xl font-bold text-gray-900">{loading ? '--' : Math.round(kpis?.pendingReview ?? 0)}</div>
167→          </div>
