211→interface GroupedPoint {
212→  pointId: string;
213→  events: AdminSubmissionEvent[];
214→  category: AdminSubmissionEvent['event']['category'];
215→  siteName: string;
216→  latestEvent: AdminSubmissionEvent;
217→  createdEvent: AdminSubmissionEvent | null;
218→  enrichEvents: AdminSubmissionEvent[];
219→  allPhotos: { url: string; eventType: string; createdAt: string; metadata: SubmissionPhotoMetadata | null }[];
220→}
